#include<stdio.h>
int main() {
	int M,N,min,max;
	scanf("%d%d",&N,&M);
	if(M==0 && N==0)
		printf("0 0\n");
	else if(N==0)
		printf("Impossible\n");
	else {
		if(M==0) {
			min=N;
			max=N;
		}
		else {
			if(N>=M) {
				min=N;
				max=N+M-1;
			}
			else {
				min=M;
				max=N+M-1;
			}
		}
		printf("%d %d\n",min,max);
	}
	return 0;
}

